INSERT INTO "KnowledgeDocuments" ("FileName","FileType","Category","ContentPreview","RuleCount","Status","UploadedAt","UploadedBy")
INSERT INTO "FortuneRules" ("Category","Subcategory","Title","ConditionText","ResultText","SourceFile","Tags","IsActive","SortOrder","CreatedAt","UpdatedAt") VALUES
  ('紫微',NULL,'（三）太陽屬陽火，乃日之精，司官祿之主，乃中天主星。',NULL,'（三）太陽屬陽火，乃日之精，司官祿之主，乃中天主星。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'太陽陽火，主權貴，男以之為父星，女以之為夫星，入命喜白日生人吉，夜生人即在廟旺之地，亦需扣分，以卯辰巳為旺，午為廟，未申宮即偏垣西下，主人作為，先勤後惰，有使無終，酉西沒不利，戌亥子則名失揮，多費心勞力，是非亦眾，若在逢煞沖破，主人眼目有傷，此星最喜會祿存，及三台八座，得一同度，即可增輝，有聲名，入命於旺地，主人少年紅白或黃紅色，老年赤色，圓型面，中等身材，壯碩，性剛強好動，心地慈善，言語直爽，女命得之，有男子氣概，但女命雖以之為夫星，而最喜廟旺於夫妻宮，則大吉，如正坐太陽，有奪主星之兆，多奪夫權，且易接近男性，為美中不足。又日居戌亥，月在辰巳，謂反背失陷，若有凶煞沖破大凶，且有失明之虞，但若無煞有吉，秘經有云：陰陽反背，反大貴。如日在寅宮，有巨門同度，亦作旺論，再卯乃日出扶桑格，辰巳名升殿，居午謂之日麗中天，富貴全美，因皆在廟旺之地，不怕忌星，多富而不貴：如有一二煞星來沖，雖有小疵，亦無妨大體；最忌擎羊同宮，作破局論之，太陽在旺宮，有天刑同度，多是武職榮顯，此星於病，主頭部之症，血壓太高，大腸不佳，痔漏便血，肝火過旺，或目疾，斜視失明等，於田宅，主富足隆盛，近有高樓，及一切凸出，高起之建築物，俱以吉論之。',NULL,'1.日照雷門卯辰巳地，盡生富貴名揚。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'日出於卯，有天梁同度，又名日出扶桑，白日生人大吉，更喜有祿馬來合，以壬年生人化祿，並天魁入命，祿存與太陰旺地，在亥來合，為上格。乙生人祿存並化權入命，財逢化忌，旺宮不忌，亦吉；辛生人化權入命，祿存對宮來合，事業未宮無正星，借用丑宮巨門化祿為用，亦吉；最忌庚生人，雖有化祿入命，因擎羊在酉對方來沖，多凶險，加煞夭壽橫死。辰宮以癸生人魁鉞入命，財宮祿存並巨門化權為上格，丁生人對宮太陰化祿來朝亦吉，乙生人擎羊入命，對方太陰化忌不利，巳宮，以辛生人為雙祿朝元為上格，壬生人天鉞入命，雙祿來合亦吉；庚生人，日月化祿科會合，且申宮紫府祿存來暗合亦吉，但事業之太陰有擎羊同度，宜軍職，商人則事業多成敗風波。',NULL,'2.太陽居午，日麗中天，有專權之貴，敵國之富。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'午宮廟地，光芒萬丈，其吉可知，忌逢空亡，喜晝生人，以癸生人對方子宮天梁祿存來朝，事業逢巨門化權及己生人祿存同度，對方天梁化科來照，均是上格，辛生人化權入命，化祿並擎羊於事業，宜武職亦富，丁生人祿存入命，財宮寅方無正星，借用福德之太陰天機，有科祿之吉，大富；若庚生人化祿入命，但截空亦在命宮，多虛名需利，若加煞，亦平常之人也。',NULL,'3.太陽化忌，是非日有目還傷。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'日月二星，又主人之雙目，化忌，乃是非及多管之宿，太陽陷地之命，本是辛勞，在化忌，多是眼目有傷，加煞失明，若在旺地化忌加煞，亦多有斜眼，吊眼等；如旺地有煞無忌，亦多色盲，近視，散光之症。',NULL,'4.日落未申在命垣，為人先勤後惰。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'太陽在未，有太陰同度，必先考其人之型態，若如太陽之象，當作先勤後惰論，如似太陰之型態，外貌文靜，帶羞，而內在性急，則不做此論。申宮有巨門同，西沒而逢暗宿，大是不利，即或加吉，有富貴亦是作事有首無尾，好吹噓，結局仍不佳也。',NULL,'5.太陽會文昌於官祿，皇殿朝班。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'二星旺地於事業，主貴，多是皇帝，元首之「近薩」，文昌陰辛金不忌陽火，若文曲之陰水，雖不剋太陽，但不如文昌之吉也。且太陽多主武職榮顯，加文星，允文允武，可謂全材。',NULL,'6.日巳月酉安命丑，穩步蟾宮。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'蟾宮可折桂，指金榜題名之意，丑安命無煞星沖破，天梁雖閒，而財宮逢日月逢宮大吉，此類格局，多名利兼收之士，尤以甲年生人，陀羅入命，雙祿前後雙夾，陀羅金入金庫不妨，事業旺宮，化忌不忌，兼是坐貴向貴，即魁鉞，大吉（圖一）。',NULL,'7.日卯月亥，安命未宮多折桂。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'太陽在卯，有天梁同度，則太陰單守在亥，若未宮安命，日月旺地來朝，吉，但此格局，命無正星，最忌。有煞守命，尤以擎羊為最，做破局論之，且多飛災是非，以壬年生人雙祿在日月同度來朝最吉，丙生人，對方天同化祿來照亦吉，但較次之。',NULL,'8.日月同未，安命丑，侯伯之材。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'日月同宮，不宜守命，若在未，立命丑宮，或在丑，安命在未，吉扶亦貴，古以公為最上，侯伯次之，比之現代之廳局長之類，此類格局，以日月在丑，命在未者較佳，因三合巨機在卯為入廟，如反之，則巨機在酉為敗地，美中不足也。',NULL,'9.日月身命居丑未，三方無吉反為凶。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'日月守命於丑未宮，奪父母夫妻之宿於本身，必有吉星祿馬來扶方吉，若無吉星，縱無煞亦不利，加煞刑剋夭壽，如丁生人立命未宮，日月守照有擎羊，主人離財散，加之財宮有化忌，亦不利。',NULL,'10.日月夾命，不權即富。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'太陽乃官祿之主，主貴，而太陰乃財帛之主，主富。二星夾命於旺地，主財權皆隆，如人立命未宮，天府坐守，太陽居午，太陰在申，前後相夾，及立命丑宮，武曲貪狼守命，太陽巨門在寅，太陰天同居子，前後來夾，無煞沖破命垣，均是富貴雙全。至若太陽巨門在申，太陰天同居午之陷地，夾未宮武貪之命垣，若本命無吉，均是虛名虛利，或富而不貴，及天府在丑，太陽居子，及太陰在寅來夾，亦做此論。',NULL,'11.太陽居於福德，近貴榮財。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'福德宮，乃財之來源，若太陽旺地逢之，財源極旺，且太陽主貴，多得貴人之財，故曰：近貴榮財，陷地不作此論。',NULL,'福德宮，乃財之來源，若太陽旺地逢之，財源極旺，且太陽主貴，多得貴人之財，故曰：近貴榮財，陷地不作此論。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'（八）太陰，陰水，中天主星，為田宅之主宰，化氣曰富，又為母星，男為妻宿。',NULL,'（八）太陰，陰水，中天主星，為田宅之主宰，化氣曰富，又為母星，男為妻宿。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'太陰為財星，又主一生之快樂享受，如入命，必先考其上弦、或下弦，及宜夜生人，白日出生，雖在旺地，亦需扣分，最喜會祿存，及三台八座，主能增其光輝，此星為人之母宿，男又以之為妻星，入命為人少年面青白色，老年青黑色，圓臉帶方，中身材，微胖，外貌文靜，怕羞，內心好動性急，好享受，多飄泊，且易與女性接近，身宮居之，多有隨娘繼拜離祖過房等情，若在陷地，與文曲同宮。多作九流之術士。此星卯辰巳午為失輝，酉戌亥子為廟旺之鄉，丑未宮有太陽同為平和之地，加吉亦佳，煞沖不利。凡人命得太陰廟旺於妻宮，主妻賢而有內助，兼本身一生多艷遇加文曲，則可影響對方之事業宮，主貴，若在陷地，則不作此論，比星最忌與擎羊同度，主財。逢破，且為母妻女之星沖破，家中陰人有刑剋，傷亡，太陰於病，有陰虧，糖尿、疝氣，濕氣下注﹒肝旺目疾，及水膨等症，於田宅主富，近窪低之地，有水坑水道，澤溪，井泉及光線不足之處。',NULL,'1.太陰居子，水潭桂萼，丙丁之人夜生，富貴忠良。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'太陰居子，有天同福星同度，皆是入廟，夜生，則丙年之人，權祿加會（加文昌更吉），但因羊陀在午辰來沖，多主武職榮顯，且若加煞多﹒恐有橫死之象，丁生人科權祿三合，祿存來照，當富貴雙全，且為人忠良原道，如癸生入有祿存同度乘旺，主大富。',NULL,'2.月朗天門於亥地，登雲職當大權。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'太陰在亥旺地，乃月朗天門之格，富貴權隆，以王年生人雙祿會合，并魁鉞互見為上格，乙生人雙祿來合﹒化忌入命，旺地不忌，多富少貴，丙生人天魁入命來旺，祿存來朝，財宮無正星，借對方之化祿為用，亦是主富。',NULL,'3.太陰同文曲於妻官，蟾宮折桂。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'此必二星入廟之妻官，方成蟾宮折桂之局﹒主貴，妻宮正照官祿，故其有助力，但若官祿之正星被惡煞沖破，則不能貴矣，此局主美賢之妻，且一生多艷遇，本人文章令盛，加魁鉞得妻財。',NULL,'4.太陰羊陀，必主人離財散。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'財、母、妻之星，逢擎羊之刑，或陀羅之忌，又名夭壽煞，當破財而人口損傷，死亡，如在廟旺之地，當可無防大體，若居陷弱之鄉，則刑耗喪訟，連綿而來，以至一敗塗地。',NULL,'5.太陰居戌無煞湊，丁己生人富而且壽。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'戌宮廟旺，丁生人魁鉞夾命，三合化科權祿，并祿存於財宮，富中有貴，己生人明祿暗祿，事業有天梁化科來合亦吉，兼之男命逆行大限，廿六之後，一帆風順，多富。',NULL,'6.月曜天機﹒女淫貧。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'女命如逢二星陷弱於身命之宮，如天機在丑，太陰居卯，非但貧而且淫濫，即或廟旺，如大陰在戌，天機居午之身命，亦有富貴，但淫慾不免，加煞則三嫁而不足也。',NULL,'7.日月疾厄命宮空﹒腰駝目瞽。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'人命若逢日月同度，於丑或未之疾厄宮，而本命七殺單守於子或午合，卻有截空，或旬空於命垣，必主目瞽，或駝背之殘疾，再若命空，而太陽或太陰單守，亦有殘疾，但較輕。',NULL,'8.日月羊陀，多剋親。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'此訣之義，與前之「太陰羊陀，必主人離財散」者同，今再加太陽又剋父，女剋夫﹒如行運逢之，全家不安，兼有刑傷。',NULL,'9.日月夾命，夾財，不權即富。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'日月相夾者，有四局，以天府居未，日午月申相夾，及武貪居丑，太陽巨門在寅，太陰天同於子來夾﹒此二局因皆在旺地，當主權富，於財帛亦主富足，即或有化忌，或二煞星相沖，不妨也，另有天府在丑，日子月寅及武貪在未，日申月午之相夾，日月陷地，虛名也，不貴，本命加吉另作他局論﹒不然未必有助。',NULL,'10.陰陽會昌曲，出世榮華。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'出世指處世，未必出身於富貴之家也，日月旺地，有文昌及文曲同度，或會合，主一生處於上層階級，多風光，有名譽之美，享用亦佳，如日月陷地逢昌由，則主華而不實矣。',NULL,'11.太陰火鈴同位，反成十惡。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'此指人之性格，且必太陰之癸水陷弱，而有火星沖破，則浮猾狡詐，兼是凶殘，此類多內奸，鈴星同度，有時機警伶俐，不作凶論，若太陰旺地有火星同，生性暴烈，拗執，不作凶惡不義論。至於旺地逢鈐星更不作沖破看夾，有時主此一生多有巧遇機緣也。',NULL,'12.日月乃光明磊落之宿，為坦白無私之象。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'三星乃有光輝明亮之宿，故為人磊落坦白，且因二星不論畫夜運行不息，故亦主一生多飄泊辛勞，在外居多，如在陷地加煞﹒亦有外貌誠厚坦白，而內藏奸詐之人。',NULL,'三星乃有光輝明亮之宿，故為人磊落坦白，且因二星不論畫夜運行不息，故亦主一生多飄泊辛勞，在外居多，如在陷地加煞﹒亦有外貌誠厚坦白，而內藏奸詐之人。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'（一）紫微屬陰土，北斗之主星，在數專司爵祿',NULL,'（一）紫微屬陰土，北斗之主星，在數專司爵祿','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'紫微乃至尊之宿，又名帝座，專司官貴，即事業之星;',NULL,'紫微乃至尊之宿，又名帝座，專司官貴，即事業之星;','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'入命主，為人早年面黃白色，老年則紅黃色，或赤色，長圓臉型中等身材，而腰背多肉；',NULL,'入命主，為人早年面黃白色，老年則紅黃色，或赤色，長圓臉型中等身材，而腰背多肉；','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'性情多變動，剛柔不濟，故雖為人忠厚，而心地較小，且耳軟心活，有多方面之嗜好及興趣，亦有隨心所欲，不顧一切其它之意;',NULL,'性情多變動，剛柔不濟，故雖為人忠厚，而心地較小，且耳軟心活，有多方面之嗜好及興趣，亦有隨心所欲，不顧一切其它之意;','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'如不會左右，則不 能貴，多勞碌，有成敗，更忌有四煞在陷地，無制來沖，謂之奴欺主，多殘疾，或不善終，若人所行大限逢之，亦有此 象，軍人行限逢之，多煞沖，則多是壯烈犧牲，而得身後之哀榮。',NULL,'如不會左右，則不 能貴，多勞碌，有成敗，更忌有四煞在陷地，無制來沖，謂之奴欺主，多殘疾，或不善終，若人所行大限逢之，亦有此 象，軍人行限逢之，多煞沖，則多是壯烈犧牲，而得身後之哀榮。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'此星入命，或行限逢之，最喜會祿存，輔弼，昌曲，武曲，天相等吉星，若吉少而逢煞多，反不利。',NULL,'此星入命，或行限逢之，最喜會祿存，輔弼，昌曲，武曲，天相等吉星，若吉少而逢煞多，反不利。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'男命若落於 兄弟，子女，父母，疾厄，交友等宮，雖廟旺，亦作不利論 之，尤以交友宮，反主為人勢利，因友人皆貴，本身成逢迎之人，亦是辛勞奔馳之命也；',NULL,'男命若落於 兄弟，子女，父母，疾厄，交友等宮，雖廟旺，亦作不利論 之，尤以交友宮，反主為人勢利，因友人皆貴，本身成逢迎之人，亦是辛勞奔馳之命也；','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'福德宮男為陷弱，而女作廟旺，因男女不同，以女喜安享之故也。',NULL,'福德宮男為陷弱，而女作廟旺，因男女不同，以女喜安享之故也。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'至於紫府同宮於寅申二地，入命或落於父母，兄弟，夫妻，子女諸官，俱以主孤論斷，除非另有其他吉星，不然，父母早亡，或本身單傳獨子 ，或夫妻死別生離，或無子嗣等情，因其太旺，則過猶不及 也，至於紫微如與他星，如破軍，貪狼，七殺，天相等同宮，當另於他星之篇內，另作說明；',NULL,'至於紫府同宮於寅申二地，入命或落於父母，兄弟，夫妻，子女諸官，俱以主孤論斷，除非另有其他吉星，不然，父母早亡，或本身單傳獨子 ，或夫妻死別生離，或無子嗣等情，因其太旺，則過猶不及 也，至於紫微如與他星，如破軍，貪狼，七殺，天相等同宮，當另於他星之篇內，另作說明；','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'此星如在疾厄官，主有胃脾之疾，濕熱，及雜癆等症，如在田宅宮主富裕，且近有富裕之家，高樓，或土坡，微高之地，甚或名人之墳墓等，皆主吉。',NULL,'1.紫微男亥女寅宮，壬甲生人富貴同。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'男命得紫微在亥立命，當有七殺同宮，六王年生人，祿存亦在亥，且紫徽化權故吉。女命紫微在寅之命垣，當有天府同度，甲年干生人，祿存亦在寅官，兼之廉貞化祿在午，武曲化科在戌，三合來朝，自然富貴矣，但紫府同宮之女命，恐有孤意，雖是富貴，防有美中不足也。',NULL,'2.紫府武曲居財宅，更兼權祿富奢翁。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'斗數中以紫微天府武曲及雙祿為財星，故如有入於財帛及田宅之宮，再逢吉化，富裕無疑，因田宅乃藏財之所，如財宮旺，而田宅不佳，多是旺而難留，暗耗甚重。',NULL,'3.極居卯酉，劫空四煞多為脫俗之僧。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'極指紫微而言，如在卯或酉官立命，帝星在東方，西方乃失位，且必有貪狼，喜學神仙之術之宿同官，若再有劫空同於身命，逢煞星沖破，反是空門中之僧道也。此局如有火星，或鈴星同官，不作此論，反有富貴，但為人怪異。',NULL,'4.紫微七殺化權，反作禎祥。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'七殺乃孤剋之宿，僅有巳亥二宮，與紫微同宮，紫微十二宮中無失陷，僅有旺弱之分，以土去生七殺之金，且紫微能解七殺之凶而成權威，故反作吉論，以巳官較亥宮更佳，因火以生土，土以生金之故也。',NULL,'5.紫徽破軍，無左右，無吉曜，凶惡胥吏之徒。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'紫徽破軍僅限於丑末二官，方有同宮，例如有吉星祿馬來會合，乃斗數中之上格﹒若不逢吉星，如更無左右來會合，主為公門胥吏，為人凶暴狡詐，且是多淫慾。',NULL,'6.紫府夾命為貴格。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'紫府二星，乃南北二斗之至尊，如在前後夾─命垣，主富貴雙全，然此格僅限立命寅申二宮，且一生多貴助，如紫微居丑未二宮，有破軍同，天府在卯酉來夾命，但命垣無正星，借用對宮之天同天梁為用，必身宮廟旺，且是無破，再紫微在卯酉有貪狼同，天府居丑未相夾，命有太陰天機在寅申，並非入廟，因會合天同天梁、成「探花格」亦必有吉多來扶方貴，不然，亦是平常之人也。',NULL,'7.桃花犯主為至淫，男女邪淫。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'主即帝座之謂，桃花即指貪狼也，但數中桃花之星頗多，如廉貞，又名次桃花，天姚是風騷之宿，文曲亦是桃花，咸池又名桃花煞﹒但紫貪之命，主必有淫行，必身宮及三合見桃花之星多，來會合者方是，但仍有富貴貧賤之差異。',NULL,'8.紫微居午無刑忌，甲己丁人命至公卿。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'紫微居午，帝居南極但因火生土，亦旺，如無刑，即羊陀，忌即化忌，來沖破，則甲生人祿存與武曲化科入於財宮，天府廉貞化祿於事業，乃雙祿朝元格，及己年生人祿存入命，武曲化祿於財宮，亦主富貴，丁年生人，祿存入命，亦主富中取貴。',NULL,'9.紫府朝垣活碌逢，終生福厚居三公。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'朝垣者、即三合來照之意也，紫府來朝無煞大吉，例如：立命在寅、武曲天相守照，午宮事業有紫微，戍宮財帛逢天府廉貞，若不逢四煞來沖破，甲年生人，科權綠并祿存來會合，做極品之貴論。',NULL,'10.紫破辰成，君臣不義。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'辰為天羅，戌是地網，不利紫微帝星，帝居辰則破軍必居戌，帝戌則破軍必居辰，凡人身命分居辰戌而遇紫破，主為臣不忠，先貴而終敗，若命得帝星而身不逢破軍，當另作別論，但必可富而不能貴也。',NULL,'11.紫微七殺加空亡，虛名受蔭。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'前紫微七殺化權，反為禎祥之說，但若再加截路空亡，或旬中空亡，則其人祖業雖佳，得受蔭福，而本人並無獨創建樹，虛有美名也。',NULL,'12.君臣慶會，富貴全美。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'紫微以左右為相，天相昌曲為從，以魁鉞為傳令，天府為帑藏，祿馬為掌爵之司，此數星會合身命垣，無煞沖破，乃君臣慶會之格，主有極品之貴。',NULL,'13.紫微會吉於遷移，因人而貴。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'遷移星主人出行之吉凶，亦主其人一生之遭遇與否泰，尊星入於遷移，主為人多奔波，辛勞離鄉遠出得意，亦主一生近貴人；而終得貴人之提攜而發。',NULL,'14.紫破武曲合羊陀，欺公禍亂。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'此數星合會於身命及合方，必為人好作亂喜欺詐，例如紫破命垣在丑宮，身會武曲七殺居酉，庚生人擎羊在酉，陀羅於未來沖命。但此類之命，多有橫發一時之得意，最後破敗，煞多則凶死。',NULL,'此數星合會於身命及合方，必為人好作亂喜欺詐，例如紫破命垣在丑宮，身會武曲七殺居酉，庚生人擎羊在酉，陀羅於未來沖命。但此類之命，多有橫發一時之得意，最後破敗，煞多則凶死。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'（七）天府陽土，南斗第一星，主延壽解厄司權之宿﹒又號令星。',NULL,'（七）天府陽土，南斗第一星，主延壽解厄司權之宿﹒又號令星。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'天府南斗主星，為財帛之主宰，號令星，又名祿庫，乃富貴之基，在數掌財宅及衣祿，為帝座之佐貳，能制羊陀為從，化火鈴為福，忌入空亡，則以孤論，主不吉，此星主為人，早年青白色，老年黃白色，長方險，中高身材，微胖，性外和內剛，有爭權奪利之心，且高傲異常。喜會昌曲，則可貴，逢武曲祿存，主有鉅萬之資，若與天相印星會合於身命，雖逢煞沖破，亦是田財富足。女命得之，清正巧機，旺夫盆子。秘經有云：天府是祿庫，命逢總是富，故即逢煞沖會，主其人奸詐不正，而仍多享受。此星以父母，交友宮為陷弱之鄉，兄弟宮亦平常論，於命身而會合天相，主六親不缺，衣食豐足，享用極佳，此星於疾病﹒主胃脾不佳，翻胃，胃脾寒弱﹒氣結膨脹，濕熱下注，腳腿浮腫，遇火之星主熱，逢水之星主寒，於田宅主富足，附近境遇甚佳，有高樓，微高之地，或山岡牌坊等，均作吉論之。',NULL,'1.天府戌宮無煞湊，甲己生人富萬金。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'戌宮有廉貞同度，陽土陰火并入廟而相生，廟樂之鄉，甲年生人化祿入命，祿存并化科入事業，財逢帝座，己年生人祿存并化祿於財官二地來朝，均是富中取貴之格，且是富貴揚名。若丁生人魁鉞夾命，祿存入財，主富，亦佳，最忌乙丙戊年生人羊陀沖命，加煞天折橫死，即有吉救，亦一生成敗起伏，是非眾多，尤以丙年生人，若再逢火鈴，因化忌入命，多遭刑戳。',NULL,'2.天府武曲居財宅，更兼權祿富奢翁。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'二星同度，僅子午二宮，皆是廟旺之地，若人之財帛，或田宅逢之，更有武曲化權或化祿，其富必矣，忌煞沖破，則不利。',NULL,'3.府相朝垣，食祿千鍾。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'此格以天府天相二星於財官二宮，來朝拱為最吉，且本命不宜沖破，若本命逢沖破，輕則減分，重則破格。以立命卯宮，天府居未，天相在亥廟旺之地最吉，立命酉宮，天府居丑，天相在巳，弱地次之，天相居來合，皆是府相朝垣格，最忌擎羊對沖及入命，不怕火星鈴星，甚至多富貴之造也。',NULL,'4.天府居午，戌天相來朝，甲生人一品之貴。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'天府在午有武曲同，天相在戌有帝座同，甲生人立命寅宮，廉貞加雙祿守照，財旺地，官化科，主特任之貴，但詳考此命，陽男順行為火六局，初運六至十五行丙寅忌祿沖，擎羊單守父母，有刑剋，本人多病，不利、及十六之後，行丁卯，擎羊單守，對方巨機化忌，亦不佳。廿六之後行戊辰，破軍化權﹒事業化祿，有勃興之象，但名美財虛。卅六之後，行天同在巳，梁同巳亥，福德化忌，無大發展。四十六之後，行庚午天府武曲化科化權，會合財官雙祿，方始揚眉吐氣。五十六之後，行辛未限日月守照，必吉多可福，不然平常，加煞多不利，且羊陀在財及遷移來沖，多作敗論。若女命則不喜雙祿之命垣，以太旺多專權并剋夫，即富貴亦美中不足。',NULL,'5.天府祿存昌曲會，巨萬之資。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'天府祿庫加祿存厚重之星，主大富，若加昌曲同，或三合來朝，昌曲主名聲，當有巨富之聲名，而後因富有貴。',NULL,'6.天府昌曲左右，高第恩榮。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'五星會合於身命，主富而且貴，多成就於財經界之官員，旦極得元首之信寵，如無煞沖破，一生順逐，無風波。',NULL,'7.天府天相乃為衣祿之神，為仕為官，定生亨通之兆。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'祿庫與印星最喜會合，印星又主衣食之享受，為官主操正印，故富而且貴。',NULL,'8.左府同宮，尊居萬乘。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW()),
  ('紫微',NULL,'二星同宮於廟樂之地，無煞沖破，極品之貴，左輔為陽土，故吉，如右弼乃陰水之根，與天府陽土有制，雖無不吉，總不如土與士之佳也。',NULL,'二星同宮於廟樂之地，無煞沖破，極品之貴，左輔為陽土，故吉，如右弼乃陰水之根，與天府陽土有制，雖無不吉，總不如土與士之佳也。','太陽太陰紫微天府.docx',NULL,true,0,NOW(),NOW());